export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

type Track = { readonly id: string; readonly title: string };

type AlbumState =
  | { status: 'draft'; tracks: readonly Track[] }
  | { status: 'released'; tracks: readonly Track[]; releasedAt: string };

type AlbumCommand =
  | { type: 'AddTrack'; track: Track }
  | { type: 'Release'; releasedAt: string };

type AlbumEvent =
  | { type: 'TrackAdded'; track: Track }
  | { type: 'Released'; releasedAt: string };

export class AlbumInvariantError extends Error {}

export const albumDecider: Decider<AlbumCommand, AlbumEvent, AlbumState> = {
  initialState: { status: 'draft', tracks: [] },
  decide(command, state): AlbumEvent[] {
    switch (command.type) {
      case 'AddTrack':
        if (state.status !== 'draft') throw new AlbumInvariantError('album frozen');
        return [{ type: 'TrackAdded', track: command.track }];
      case 'Release':
        if (state.status === 'released') throw new AlbumInvariantError('already released');
        if (state.tracks.length === 0) throw new AlbumInvariantError('no tracks');
        return [{ type: 'Released', releasedAt: command.releasedAt }];
      default: {
        const _exhaustive: never = command;
        return _exhaustive;
      }
    }
  },
  evolve(state, event): AlbumState {
    switch (event.type) {
      case 'TrackAdded':
        return state.status === 'draft'
          ? { status: 'draft', tracks: [...state.tracks, event.track] }
          : state;
      case 'Released':
        return { status: 'released', tracks: state.tracks, releasedAt: event.releasedAt };
      default: {
        const _exhaustive: never = event;
        return _exhaustive;
      }
    }
  },
};
