type ConcertState =
  | { status: 'scheduled'; capacity: number; sold: number }
  | { status: 'started' }
  | { status: 'finished' }
  | { status: 'cancelled' };

type ConcertCommand =
  | { type: 'SellTicket'; qty: number }
  | { type: 'Start' }
  | { type: 'Cancel'; reason: string };

type ConcertEvent =
  | { type: 'TicketsSold'; qty: number }
  | { type: 'Started' }
  | { type: 'Cancelled'; reason: string };

export class ConcertInvariantError extends Error {}

export function decide(command: ConcertCommand, state: ConcertState): ConcertEvent[] {
  switch (command.type) {
    case 'SellTicket':
      if (state.status !== 'scheduled') throw new ConcertInvariantError('not selling');
      if (state.sold + command.qty > state.capacity) throw new ConcertInvariantError('sold out');
      return [{ type: 'TicketsSold', qty: command.qty }];
    case 'Start':
      if (state.status !== 'scheduled') throw new ConcertInvariantError('cannot start');
      return [{ type: 'Started' }];
    case 'Cancel':
      if (state.status === 'started' || state.status === 'finished')
        throw new ConcertInvariantError('too late to cancel');
      if (state.status === 'cancelled') return [];
      return [{ type: 'Cancelled', reason: command.reason }];
    default: {
      const _exhaustive: never = command;
      return _exhaustive;
    }
  }
}
