interface StoredEvent { readonly type: string; readonly data: unknown }
interface AppendResult { readonly nextRevision: bigint }

interface EventStore {
  readStream(stream: string): AsyncIterable<{ event: StoredEvent; revision: bigint }>;
  appendToStream(
    stream: string,
    events: readonly StoredEvent[],
    opts: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<AppendResult>;
}

export class ConcurrencyConflict extends Error {}

interface StoreConflict { readonly kind: 'conflict' }
function isConflict(e: unknown): e is StoreConflict {
  return typeof e === 'object' && e !== null && (e as { kind?: unknown }).kind === 'conflict';
}

export async function appendFanClubEvents(
  store: EventStore,
  stream: string,
  events: readonly StoredEvent[],
): Promise<bigint> {
  let latest: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) latest = revision;
  try {
    const res = await store.appendToStream(stream, events, { expectedRevision: latest });
    return res.nextRevision;
  } catch (err) {
    if (isConflict(err)) throw new ConcurrencyConflict('fan-club stream moved');
    throw err;
  }
}
