import { Effect } from 'effect';

type DropEvent = { type: 'DropAnnounced'; sku: string } | { type: 'DropSoldOut'; sku: string };
type DropCommand = { type: 'MarkSoldOut'; sku: string };
type DropState = { readonly sku: string; readonly soldOut: boolean };

const initial: DropState = { sku: '', soldOut: false };

function evolve(state: DropState, event: DropEvent): DropState {
  switch (event.type) {
    case 'DropAnnounced': return { sku: event.sku, soldOut: false };
    case 'DropSoldOut': return { ...state, soldOut: true };
    default: { const _e: never = event; return _e; }
  }
}

function decide(cmd: DropCommand, state: DropState): DropEvent[] {
  return state.soldOut ? [] : [{ type: 'DropSoldOut', sku: cmd.sku }];
}

interface EventStore {
  readStream(s: string): Promise<readonly DropEvent[]>;
  appendToStream(s: string, evs: readonly DropEvent[]): Promise<void>;
}

export const handle = (store: EventStore, streamName: string, cmd: DropCommand) =>
  Effect.gen(function* () {
    const events = yield* Effect.promise(() => store.readStream(streamName));
    const state = events.reduce(evolve, initial);
    const produced = decide(cmd, state);
    if (produced.length > 0) {
      yield* Effect.promise(() => store.appendToStream(streamName, produced));
    }
    return produced;
