export class ConcurrencyConflict extends Error {}

interface Conflict { readonly kind: 'conflict' }
function isConflict(e: unknown): e is Conflict {
  return typeof e === 'object' && e !== null && (e as { kind?: unknown }).kind === 'conflict';
