  store: EventStore,
  stream: string,
  events: readonly StoredEvent[],
): Promise<bigint> {
  let latest: bigint | 'no_stream' = 'no_stream';
  for await (const { revision } of store.readStream(stream)) latest = revision;
  try {
    const res = await store.appendToStream(stream, events, { expectedRevision: latest });
    return res.nextRevision;
  } catch (err) {
    if (isConflict(err)) throw new ConcurrencyConflict('venue booking moved');
    throw err;
  }
